            Email = request.Email,
            Status = request.Status,
            AccessPoint = request.AccessPoint,
            Bridge = request.Bridge,
            UserRouter = request.UserRouter,
            Identification = request.Identification,
            UserName = request.UserName,
            Password = request.Password,
            Address = request.Address,
            Note = request.Note,
            IsSendNotificationEnabled = request.IsSendNotificationEnabled,
            IsSendSmsEnabled = request.IsSendSmsEnabled,
            IsAutoDisconnectEnabled = request.IsAutoDisconnectEnabled,
            ActiveTo = request.ActiveTo,
            MacAddress = request.MacAddress,
            IpAddress = request.IpAddress,
            PoolId = request.PoolId,
            UserGroupId = request.UserGroupId,
            LocationId = request.LocationId,
            NetworkId = request.NetworkId,
            RouterId = request.RouterId,
            UsagePolicyId = request.UsagePolicyId,
            ServiceId = request.ServiceId,
            ImageId = request.ImageId,
            IdImageId = request.IdImageId,
