        var entity = await context.Customers
            .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken)
            .ConfigureAwait(false) ?? throw new NotFoundErrorException(Messages.NotFound);

        entity.FullName = request.FullName;
        entity.Mobile = request.Mobile;
        entity.Email = request.Email;
        entity.Status = request.Status;
        entity.AccessPoint = request.AccessPoint;
        entity.Bridge = request.Bridge;
        entity.UserRouter = request.UserRouter;
        entity.Identification = request.Identification;
        entity.UserName = request.UserName;
        entity.Password = request.Password;
        entity.Address = request.Address;
        entity.Note = request.Note;
        entity.IsSendNotificationEnabled = request.IsSendNotificationEnabled;
        entity.IsSendSmsEnabled = request.IsSendSmsEnabled;
        entity.IsAutoDisconnectEnabled = request.IsAutoDisconnectEnabled;
        entity.ActiveTo = request.ActiveTo;
        entity.MacAddress = request.MacAddress;
        entity.IpAddress = request.IpAddress;
        entity.PoolId = request.PoolId;
        entity.UserGroupId = request.UserGroupId;
