        entity.ServiceId = request.ServiceId;
        entity.ImageId = request.ImageId;
        entity.IdImageId = request.IdImageId;
        entity.ManagedByUserId = request.ManagedByUserId;

        context.Customers.Update(entity);

        if (context.HasChanges())
        {
