namespace Axions.Core.Features.Customers.Commands.DeleteCustomer;

/// <summary>
/// DeleteCustomerCommand.
/// </summary>
public class DeleteCustomerCommand: IRequest
{
    /// <summary>
    /// Gets or sets Id.
    /// </summary>
    public long Id { get; set; }
}

/// <summary>
/// Handler for DeleteCustomerCommand.
/// </summary>
public class DeleteCustomerCommandHandler(ApplicationDbContext context) : IRequestHandler<DeleteCustomerCommand>
{
    #region Handler

    public async Task Handle(DeleteCustomerCommand request, CancellationToken cancellationToken)
    {
        var entity = await context.Customers.FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken).ConfigureAwait(false)
            ?? throw new NotFoundErrorException(Messages.NotFound);

        entity.IsDeleted = true;
        context.Customers.Update(entity);

        if (!context.HasChanges())
            return;

        int saved = await context.SaveChangesAsync(cancellationToken).ConfigureAwait(false);
        if (saved < 0)
            throw new InternalApplicationErrorException(Messages.SaveFailed);
    }

    #endregion
}

