namespace Axions.Core.Features.Customers.Queries.GetCustomers;

/// <summary>
/// GetsCustomersQuery
/// </summary>
public class GetCustomersQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<CustomerDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Customer, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Customer>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Customer>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.FullName) && x.FullName!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Mobile) && x.Mobile!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Email) && x.Email!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.UserName) && x.UserName!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.IpAddress) && x.IpAddress!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetCustomersQuery.
/// </summary>
public class GetCustomerQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetCustomersQuery, BaseResultDto<PaginatedResult<CustomerDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<CustomerDto>>> Handle(GetCustomersQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Customers
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Customer, CustomerDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<CustomerDto>>();
    }
}

