using System.Linq.Expressions;
using AutoMapper;
using Axions.Core.Common.Data;
using Axions.Core.Common.Extensions;
using Axions.Core.Common.Predicates;
using Axions.Core.Features.Common.Dtos;
using Axions.Core.Features.Routers.Dtos;
using Axions.Core.Features.Routers.Entities;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;

namespace Axions.Core.Features.Routers.Queries.GetRouters;

/// <summary>
/// GetsRoutersQuery
/// </summary>
public class GetRoutersQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<RouterDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Router, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Router>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Router>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.IpAddress) && x.IpAddress!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.ProfileIpAddress) && x.ProfileIpAddress!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetRoutersQuery.
/// </summary>
public class GetRouterQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetRoutersQuery, BaseResultDto<PaginatedResult<RouterDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<RouterDto>>> Handle(GetRoutersQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Routers
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Router, RouterDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<RouterDto>>();
    }
}

