namespace Axions.Core.Features.Plans.Queries.GetPlans;

/// <summary>
/// GetsPlansQuery
/// </summary>
public class GetPlansQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<PlanDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Plan, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Plan>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Plan>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Title) && x.Title!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.PeriodType) && x.PeriodType!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetPlansQuery.
/// </summary>
public class GetPlanQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetPlansQuery, BaseResultDto<PaginatedResult<PlanDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<PlanDto>>> Handle(GetPlansQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Plans
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Plan, PlanDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<PlanDto>>();
    }
}

