/// <summary>
/// GetsDiscountsQuery
/// </summary>
public class GetDiscountsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<DiscountDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Discount, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Discount>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Discount>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Type) && x.Type!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Code) && x.Code!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetDiscountsQuery.
/// </summary>
public class GetDiscountQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetDiscountsQuery, BaseResultDto<PaginatedResult<DiscountDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<DiscountDto>>> Handle(GetDiscountsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Discounts
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Discount, DiscountDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<DiscountDto>>();
    }
}

