/// <summary>
/// GetsSupportRequestsQuery
/// </summary>
public class GetSupportRequestsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<SupportRequestDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<SupportRequest, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<SupportRequest>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<SupportRequest>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Subject) && x.Subject!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Priority) && x.Priority!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

