/// <summary>
/// GetsSuppliersQuery
/// </summary>
public class GetSuppliersQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<SupplierDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Supplier, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Supplier>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Supplier>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Email) && x.Email!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Mobile) && x.Mobile!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.ContactPerson) && x.ContactPerson!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetSuppliersQuery.
/// </summary>
public class GetSupplierQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetSuppliersQuery, BaseResultDto<PaginatedResult<SupplierDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<SupplierDto>>> Handle(GetSuppliersQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Suppliers
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Supplier, SupplierDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<SupplierDto>>();
    }
}

