/// <summary>
/// GetsAreasQuery
/// </summary>
public class GetAreasQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<AreaDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Area, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Area>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Area>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.ZoneCode) && x.ZoneCode!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetAreasQuery.
/// </summary>
public class GetAreaQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetAreasQuery, BaseResultDto<PaginatedResult<AreaDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<AreaDto>>> Handle(GetAreasQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Areas
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Area, AreaDto>(mapper, request, cancellationToken)
