/// <summary>
/// GetsAccessPointsQuery
/// </summary>
public class GetAccessPointsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<AccessPointDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<AccessPoint, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<AccessPoint>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<AccessPoint>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.IpAddress) && x.IpAddress!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.MacAddress) && x.MacAddress!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Model) && x.Model!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetAccessPointsQuery.
/// </summary>
public class GetAccessPointQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetAccessPointsQuery, BaseResultDto<PaginatedResult<AccessPointDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<AccessPointDto>>> Handle(GetAccessPointsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.AccessPoints
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<AccessPoint, AccessPointDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<AccessPointDto>>();
    }
}

