using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;

namespace Axions.Core.Features.Exports.Queries.GetExports;

/// <summary>
/// GetsExportsQuery
/// </summary>
public class GetExportsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<ExportDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Export, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Export>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Export>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Type) && x.Type!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetExportsQuery.
/// </summary>
public class GetExportQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetExportsQuery, BaseResultDto<PaginatedResult<ExportDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<ExportDto>>> Handle(GetExportsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Exports
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Export, ExportDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<ExportDto>>();
