}

/// <summary>
/// Handler for DeletePromotionCommand.
/// </summary>
public class DeletePromotionCommandHandler(ApplicationDbContext context) : IRequestHandler<DeletePromotionCommand>
{
    #region Handler

    public async Task Handle(DeletePromotionCommand request, CancellationToken cancellationToken)
    {
        var entity = await context.Promotions.FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken).ConfigureAwait(false)
            ?? throw new NotFoundErrorException(Messages.NotFound);

        entity.IsDeleted = true;
        context.Promotions.Update(entity);

