/// <summary>
/// GetsPromotionsQuery
/// </summary>
public class GetPromotionsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<PromotionDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Promotion, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Promotion>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Promotion>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.TargetAudience) && x.TargetAudience!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetPromotionsQuery.
/// </summary>
public class GetPromotionQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetPromotionsQuery, BaseResultDto<PaginatedResult<PromotionDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<PromotionDto>>> Handle(GetPromotionsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Promotions
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Promotion, PromotionDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<PromotionDto>>();
    }
}

