using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;

namespace Axions.Core.Features.Gateways.Queries.GetGateways;

/// <summary>
/// GetsGatewaysQuery
/// </summary>
public class GetGatewaysQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<GatewayDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Gateway, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Gateway>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Gateway>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.IpAddress) && x.IpAddress!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.MacAddress) && x.MacAddress!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetGatewaysQuery.
/// </summary>
public class GetGatewayQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetGatewaysQuery, BaseResultDto<PaginatedResult<GatewayDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<GatewayDto>>> Handle(GetGatewaysQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Gateways
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Gateway, GatewayDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<GatewayDto>>();
    }
}

