namespace Axions.Core.Features.DnsServers.Queries.GetDnsServers;

/// <summary>
/// GetsDnsServersQuery
/// </summary>
public class GetDnsServersQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<DnsServerDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<DnsServer, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<DnsServer>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<DnsServer>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.PrimaryIp) && x.PrimaryIp!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.SecondaryIp) && x.SecondaryIp!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetDnsServersQuery.
/// </summary>
public class GetDnsServerQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetDnsServersQuery, BaseResultDto<PaginatedResult<DnsServerDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<DnsServerDto>>> Handle(GetDnsServersQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.DnsServers
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<DnsServer, DnsServerDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<DnsServerDto>>();
    }
}

