using System.Linq.Expressions;
using AutoMapper;
using Axions.Core.Common.Data;
using Axions.Core.Common.Extensions;
using Axions.Core.Common.Predicates;
using Axions.Core.Features.Common.Dtos;
using Axions.Core.Features.Thresholds.Dtos;
using Axions.Core.Features.Thresholds.Entities;
using MediatR;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;

namespace Axions.Core.Features.Thresholds.Queries.GetThresholds;

/// <summary>
/// GetsThresholdsQuery
/// </summary>
public class GetThresholdsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<ThresholdDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Threshold, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Threshold>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Threshold>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.MetricType) && x.MetricType!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Operator) && x.Operator!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetThresholdsQuery.
/// </summary>
public class GetThresholdQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetThresholdsQuery, BaseResultDto<PaginatedResult<ThresholdDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<ThresholdDto>>> Handle(GetThresholdsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Thresholds
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Threshold, ThresholdDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<ThresholdDto>>();
    }
}

