    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets Status.
    /// </summary>
    public string? Status { get; set; }

    public Expression<Func<Event, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Event>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Event>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Title) && x.Title!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Type) && x.Type!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Status) && x.Status!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.EntityType) && x.EntityType!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (!Status.IsNullOrEmpty())
            predicate = predicate.And(x => !string.IsNullOrEmpty(x.Status) && x.Status == Status);

        return predicate;
    }
}

/// <summary>
/// Handler for GetEventsQuery.
/// </summary>
public class GetEventQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetEventsQuery, BaseResultDto<PaginatedResult<EventDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<EventDto>>> Handle(GetEventsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Events
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Event, EventDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<EventDto>>();
    }
}

