}

/// <summary>
/// Update Webhook Command Handler.
/// </summary>
public class UpdateWebhookCommandHandler(ApplicationDbContext context) : IRequestHandler<UpdateWebhookCommand, BaseResultDto<long>>
{
    #region Handler

    public async Task<BaseResultDto<long>> Handle(UpdateWebhookCommand request, CancellationToken cancellationToken)
    {
        var entity = await context.Webhooks
            .FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken)
            .ConfigureAwait(false) ?? throw new NotFoundErrorException(Messages.NotFound);

        entity.Name = request.Name;
        entity.Url = request.Url;
        entity.Secret = request.Secret;
        entity.Events = request.Events;
        entity.Status = request.Status;
        entity.LastTriggeredAt = request.LastTriggeredAt;
        entity.Description = request.Description;

        context.Webhooks.Update(entity);

        if (context.HasChanges())
        {
            var result = await context.SaveChangesAsync(cancellationToken).ConfigureAwait(false);
            if (result < 0)
                throw new InternalApplicationErrorException(Messages.SaveFailed);
        }

        return new BaseResultDto<long>(entity.Id);
    }

    #endregion
}

