namespace Axions.Core.Features.Webhooks.Commands.DeleteWebhook;

/// <summary>
/// DeleteWebhookCommand.
/// </summary>
public class DeleteWebhookCommand: IRequest
{
    /// <summary>
    /// Gets or sets Id.
    /// </summary>
    public long Id { get; set; }
}

/// <summary>
/// Handler for DeleteWebhookCommand.
/// </summary>
public class DeleteWebhookCommandHandler(ApplicationDbContext context) : IRequestHandler<DeleteWebhookCommand>
{
    #region Handler

    public async Task Handle(DeleteWebhookCommand request, CancellationToken cancellationToken)
    {
        var entity = await context.Webhooks.FirstOrDefaultAsync(x => x.Id == request.Id, cancellationToken).ConfigureAwait(false)
            ?? throw new NotFoundErrorException(Messages.NotFound);

        entity.IsDeleted = true;
        context.Webhooks.Update(entity);

        if (!context.HasChanges())
            return;

        int saved = await context.SaveChangesAsync(cancellationToken).ConfigureAwait(false);
        if (saved < 0)
            throw new InternalApplicationErrorException(Messages.SaveFailed);
    }

    #endregion
}
